	## start server rate.example.com
	server {
		server_name rate.example.com ;

		http2 on;

		listen 80  ;
		listen [::]:80  ;
		listen 443  ssl;
		listen [::]:443  ssl;

		set $proxy_upstream_name "-";

		ssl_certificate_by_lua_file /etc/nginx/lua/nginx/ngx_conf_certificate.lua;

		location /health/ {

			set $namespace      "demo";
			set $ingress_name   "rate-health";
			set $service_name   "rate-echo";
			set $service_port   "80";
			set $location_path  "/health";

--
	## end server rate.example.com

	# backend for when default-backend-service is not configured or it does not have endpoints
	server {
		listen 8181 default_server reuseport backlog=4096;
		listen [::]:8181 default_server reuseport backlog=4096;
		set $proxy_upstream_name "internal";

		access_log off;

		location / {
			return 404;
		}
	}

	# default server, used for NGINX healthcheck and access to nginx stats
	server {
		# Ensure that modsecurity will not run on an internal location as this is not accessible from outside

		listen 127.0.0.1:10246;
		set $proxy_upstream_name "internal";

